  "question": "请专门写一段版本陷阱审计说明,解释旧版审批线可能导致的误判。",
  "scope": {
    "audit_object": "证券费用报销审批线版本陷阱",
    "expense_types": "all",
    "business_period": "2025-01-01 onwards",
    "organization_scope": "XX证券全部门",
    "deliverable": "版本陷阱审计说明（audit_report格式）"
  },
  "policy_questions": [
    {
      "id": "PQ-1",
      "question": "2022版与2025版费用报销审批线有何差异？",
      "policies": ["01_expense_reimbursement_2025.md", "02_expense_reimbursement_2022_deprecated.md", "03_authorization_management.md"],
      "boundaries": {
        "old_thresholds": {"dept_gm": 8000, "deputy_gm": 30000},
        "new_thresholds": {"AR01_upper": 3000, "AR02_upper": 10000, "AR03_upper": 50000, "AR04_upper": 200000},
        "effective_date": "2025-01-01",
        "repeal_date": "2025-01-01"
      }
    },
    {
      "id": "PQ-2",
      "question": "使用旧版审批线会在哪些金额区间造成误判？",
      "policies": ["02_expense_reimbursement_2022_deprecated.md", "03_authorization_management.md"],
      "boundaries": {
        "false_positive_zones": ["8000-10000 (旧线触发部门总经理,现行AR-02仅需部门经理+财务复核)", "30000-50000 (旧线触发分管副总,现行AR-03仅需部门总经理)"],
        "false_negative_zones": ["3000-8000 (旧线无特殊要求,现行AR-02需财务复核)", "10000+ (旧线8000起触发,现行10000起触发部门总经理)"]
      }
    }
  ],
  "data_questions": [
    {
      "id": "DQ-1",
      "question": "哪些报销记录落入版本陷阱金额区间？",
      "tables": ["expenses"],
      "fields": ["record_id", "amount", "expense_type", "expense_date", "reimburse_date", "employee_name", "department_name", "status"],
